        kind:og('novel:status')+','+og('novel:update_time').replace(/\s.*/,''),
        latest:og('novel:latest_chapter_name'),
        intro:og('description'),
        cover:og('image'),
        url:'https://www.miaojiang8.net'+url,
    };
});
</js>

