var paginatorHrefs = java.getString("//div[@class='f_left paginator']//a/@href") || "";

// 2. 初始化变量
var maxPage = 1;
var aid = "";
var urlPattern = /page-(\d+)-aid-(\d+)/; // 匹配 page-数字-aid-数字

// 3. 遍历链接找到“最大页码”和“相册ID”
// 分割字符串并过滤空行
var links = paginatorHrefs.split('\n');
for (var i = 0; i < links.length; i++) {
    var link = links[i].trim();
    var match = link.match(urlPattern);

    if (match) {
        var pageNum = parseInt(match[1]); // 提取页码
        var currentAid = match[2];        // 提取AID

        // 更新最大页码
        if (pageNum > maxPage) {
            maxPage = pageNum;
        }
        // 提取AID（如果还没提取到）
        if (!aid) {
            aid = currentAid;
        }
    }
}

// 4. 根据获取到的 maxPage 和 aid 生成完整的 URL 列表
if (aid && maxPage > 1) {
    for (var i = 1; i <= maxPage; i++) {
        // 拼接标准URL格式：photos-index-page-{页码}-aid-{ID}.html
        nextPageUrl.push("https://www.wn06.ru/photos-index-page-" + i + "-aid-" + aid + ".html");
    }
} else {
