var defaultIntlLinks = ['https://18comic.vip', 'https://18comic.ink'];
var defaultSeaLinks = ['https://jmcomic-zzz.one', 'https://jmcomic-zzz.org'];
var cachedPageHtml = null;

function extractLinks(pageHtml, blockRegex) {
    var links = [];
    if (!pageHtml) return links;
    var blockMatch = pageHtml.match(blockRegex);
    if (blockMatch && blockMatch[1]) {
        var blockContent = blockMatch[1];
        var linkMatches = blockContent.match(/<span>(.*?)<\/span>/g);
        if (linkMatches) {
            links = linkMatches.map(function(spanTag) {
                var domain = spanTag.replace(/<\/?span>/g, '').trim();
                return 'https://' + domain;
            }).filter(function(url) {
                return url !== 'https://';
            });
        }
    }
    return links;
}

var intlBlockRegex = /<div class="international">([\s\S]*?)<\/div>/;
var seaBlockRegex = /<div class="southeast_asia">([\s\S]*?)<\/div>/;

