jsLib:
function decodeData(result) {
    var a = result.match(/\(".*?"/)[0].slice(2, -1);
    return Xexgiy( unescape( AvuWlj(a, "%") ) );
}

function AvuWlj(str, r) {
    return r + str.match(/.{2}/g).join(r);
}

function Xexgiy(str) {
    var out = "", i = 0, len = str.length, c, char2, char3;
    while (i < len) {
        c = str.charCodeAt(i++);
        switch (c >> 4) {
        case 0:
        case 1:
        case 2:
        case 3:
        case 4:
        case 5:
        case 6:
        case 7:
            out += str.charAt(i - 1);
            break;
        case 12:
        case 13:
            char2 = str.charCodeAt(i++);
            out += String.fromCharCode(((c & 31) << 6) | (char2 & 63));
            break;
        case 14:
            char2 = str.charCodeAt(i++);
            char3 = str.charCodeAt(i++);
            out += String.fromCharCode(((c & 15) << 12) | ((char2 & 63) << 6) | (char3 & 63));
            break;
        }
    }
    return out;
}

